from typing import List

def min_column_average(matrix: List[List[int]]) -> float:
    m = len(matrix)
    n = len(matrix[0])
    min_avg = float('inf')
    for col in range(n):
        col_sum = 0
        for row in range(m):
            col_sum += matrix[row][col]
        avg = col_sum / m
        if avg < min_avg:
            min_avg = avg
    return round(min_avg, 5)

from typing import List

def min_column_average(matrix: List[List[int]]) -> float:
    return round(min(sum(col) / len(col) for col in zip(*matrix)), 5)
